import React, { useState } from "react";
import { Link } from "react-router-dom";
import "../styles/News.css";
import ReadMore from "./ReadMore"; // Import ReadMore component
import NewsCard from "./NewsCard"; // Import the new NewsCard component

const News = ({ articles }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedArticle, setSelectedArticle] = useState(null);

  const openModal = (article) => {
    setSelectedArticle(article);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedArticle(null);
  };

  // Slice the articles array to only show the first 3 articles in News
  const displayedArticles = articles.slice(0, 3);

  return (
    <div className="News">
      <h2>News & Articles</h2>
      <div className="news-container">
        {displayedArticles.map((article) => (
          <NewsCard
            key={article.id}
            article={article}
            onReadMoreClick={openModal}
          />
        ))}
      </div>
      <Link to="/more-news" className="view-more">
        View more →
      </Link>

      {isModalOpen && selectedArticle && (
        <ReadMore selectedArticle={selectedArticle} closeModal={closeModal} />
      )}
    </div>
  );
};

export default News;
